        public Point(long x, long y, long z) {
            this.x = x;
            this.y = y;
            this.z = z;
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (o == null || getClass() != o.getClass()) return false;
            Point point = (Point) o;
            return x == point.x && y == point.y && z == point.z;
        }

        @Override
        public int hashCode() {
            return Objects.hash(x, y, z);
        }
    }

    /**
     * Calculates the midpoint of two points using floor division.
     * c = [floor((x1 + x2) / 2), floor((y1 + y2) / 2), floor((z1 + z2) / 2)]
     * Since all coordinates are non-negative, integer division in Java (for positive numbers)
     * already performs floor.
     */
    private static Point calculateNextGenPoint(Point a, Point b) {
        long cx = (a.x + b.x) / 2;
        long cy = (a.y + b.y) / 2;
        long cz = (a.z + b.z) / 2;
        return new Point(cx, cy, cz);
    }

