        if (currentPoints.contains(targetPoint)) {
            return 0;
        }

        // If there is only 0 or 1 distinct initial point, no new points can be generated.
        if (currentPoints.size() <= 1) {
            return -1;
        }

        long k = 0;
        Set<Point> prevPoints = new HashSet<>(currentPoints);

        while (true) {
            k++;
            Set<Point> nextPoints = new HashSet<>();

            // Convert to list to iterate over pairs
            Point[] currentArray = prevPoints.toArray(new Point[0]);
            int n = currentArray.length;

            // Generate new points for Generation k
            // Consider every pair of *different* points a and b from Generation 0 to k-1 (i.e., prevPoints)
            for (int i = 0; i < n; i++) {
                for (int j = i + 1; j < n; j++) {
                    Point a = currentArray[i];
                    Point b = currentArray[j];

