                    // Since we are using a Set<Point> (prevPoints), all points in currentArray are distinct by coordinate.
                    // Thus, any pair (i, j) with i != j already satisfies the condition.

                    Point c = calculateNextGenPoint(a, b);
                    nextPoints.add(c);
                }
